// Seed sources to check for data-center facilities.
// Put ONE facility-specific public URL per entry: a TCEQ permit detail page,
// a county commissioners' agenda item, or a news article about a SPECIFIC
// Texas data center. (A generic homepage will return 'no facility found'.)
// For your first end-to-end test, paste one real article/permit URL below.
const sources = [
  { url: 'https://www.tceq.texas.gov/' }
];
return sources.map(s => ({ json: s }));

// Build a Gemini request that EXTRACTS one facility as strict JSON from the
// scraped page. We never republish the page — Gemini only pulls facts.
const md = ($json.data && $json.data.markdown) ? $json.data.markdown : '';
const sourceUrl = $('Take first').item.json.url;
if (!md || md.length < 50) { throw new Error('Empty scrape for ' + sourceUrl); }
const sys = [
  'You extract ONE Texas data center (or crypto-mining) facility from a scraped public web page.',
  'Output a SINGLE JSON object and nothing else (no prose, no code fences).',
  'Keys: name, operator, city, county, lat, lng, status, harm, sourceName, note.',
  'status MUST be exactly one of: "proposed", "permitted", "under-construction", "operating".',
  'Map permit language: application/pending/received/draft => "proposed"; permit issued/approved/active but not built => "permitted"; under construction/breaking ground => "under-construction"; online/operating => "operating". If unclear, use "proposed".',
  'lat/lng: include ONLY if a physical street address or explicit coordinates appear on the page; otherwise set both to null. NEVER guess or estimate coordinates.',
  'harm: a subset of ["water","air","property","noise"] supported by the page; otherwise [].',
  'note: ONE neutral factual sentence in your own words. Do not assert harm beyond what the source states.',
  'If the page is not about a specific Texas data center facility, output {"skip": true}.'
].join(' ');
const user = 'Source URL: ' + sourceUrl + '\n\nScraped page content:\n' + md.slice(0, 12000);
const body = { systemInstruction: { parts: [{ text: sys }] }, contents: [{ role: 'user', parts: [{ text: user }] }], generationConfig: { responseMimeType: 'application/json', temperature: 0.1 } };
return [{ json: { body: body, sourceUrl: sourceUrl } }];

// Parse Gemini's JSON, validate, and build the facility file + PR metadata.
const parts = $json.candidates && $json.candidates[0] && $json.candidates[0].content && $json.candidates[0].content.parts || [];
let text = parts.map(p => p.text || '').join('').trim();
text = text.replace(/^```[a-zA-Z]*\n?/, '').replace(/```$/, '').trim();
let d;
try { d = JSON.parse(text); } catch (e) { throw new Error('Bad JSON from Gemini: ' + text.slice(0, 200)); }
if (d.skip) { throw new Error('No specific data center facility found on the page.'); }
const name = (d.name || '').toString().trim();
if (!name) { throw new Error('Gemini returned no facility name.'); }
const STAT = ['proposed', 'permitted', 'under-construction', 'operating'];
const status = STAT.indexOf(d.status) !== -1 ? d.status : 'proposed';
const sourceUrl = $('Build Gemini request').item.json.sourceUrl;
let lat = Number(d.lat), lng = Number(d.lng);
const hasCoords = Number.isFinite(lat) && Number.isFinite(lng) && lat > 25.5 && lat < 36.7 && lng > -107 && lng < -93.3;
const facility = {
  name: name,
  operator: d.operator || undefined,
  city: d.city || undefined,
  county: d.county || undefined,
  lat: hasCoords ? lat : null,
  lng: hasCoords ? lng : null,
  status: status,
  harm: Array.isArray(d.harm) ? d.harm.filter(h => typeof h === 'string') : [],
  sourceUrl: sourceUrl,
  sourceName: d.sourceName || undefined,
  note: (d.note || '').toString().trim() || undefined,
  dateFound: new Date().toISOString().slice(0, 10)
};
const slug = name.toLowerCase().replace(/[^a-z0-9]+/g, '-').replace(/^-|-$/g, '').slice(0, 80);
const contentB64 = Buffer.from(JSON.stringify(facility, null, 2), 'utf8').toString('base64');
const prTitle = 'Facility: ' + name;
const prBody = 'Auto-discovered for the map — review before approving. Verify the name, status, and coordinates against the source: ' + sourceUrl + (hasCoords ? '' : '  \u26a0\uFE0F COORDINATES MISSING: add lat/lng to the JSON in this PR, or the pin will not appear on the map.');
return [{ json: { slug: slug, path: 'src/content/facilities/' + slug + '.json', contentB64: contentB64, name: name, prTitle: prTitle, prBody: prBody, needsCoords: !hasCoords } }];
